import numpy as np

def compute_perplexity(log_likelihoods):
    avg_neg_log_likelihood = -np.mean(log_likelihoods)
    return np.exp(avg_neg_log_likelihood)

def run_practice():
    ll = np.array([np.log(0.1), np.log(0.1)])
    ppl = compute_perplexity(ll)
    assert np.allclose(ppl, 10.0)
    print('[PASS] PPL validation matches expected value.')

if __name__ == '__main__':
    run_practice()
